3	import { gql } from 'graphql-request';
4	
5	const EFFICACY_ROWS_QUERY = gql`
6		query EfficacyRows($projectId: String) {
7			efficacyRows(projectId: $projectId) {
8				rowKey
9				harness
10				provider
11				model
12				attempts
13				successes
14				successRate
15				medianInputTokens
16				medianOutputTokens
17				medianDurationMs
18				medianCostUsd
19				warning {
20					kind
21					threshold
22				}
23			}
24		}
25	`;
26	
27	const COMPARISONS_QUERY = gql`
28		query Comparisons {
29			comparisons {
30				id
31				state
32				armCount
33			}
34		}
35	`;
