106	async function mockEfficacy(
107		page: import('@playwright/test').Page,
108		opts: {
109			compareFn?: (req: Record<string, unknown>) => Record<string, unknown>;
110			rows?: typeof EFFICACY_ROWS;
111		} = {}
112	) {
113		await page.route('/graphql', async (route) => {
114			const body = route.request().postDataJSON() as {
115				query: string;
116				variables?: Record<string, unknown>;
117			};
118			if (body.query.includes('NodeInfo')) {
119				await route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ data: { nodeInfo: NODE_INFO } }) });
120			} else if (body.query.includes('Projects')) {
121				await route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } } }) });
122			} else if (body.query.includes('EfficacyRows') || body.query.includes('efficacyRows')) {
123				await route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ data: { efficacyRows: opts.rows ?? EFFICACY_ROWS } }) });
124			} else if (body.query.includes('EfficacyAttempts') || body.query.includes('efficacyAttempts')) {
125				await route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ data: { efficacyAttempts: ATTEMPTS_DETAIL } }) });
126			} else if (body.query.includes('ComparisonDispatch') || body.query.includes('comparisonDispatch')) {
127				const result = opts.compareFn
128					? opts.compareFn(body.variables ?? {})
129					: { id: 'cmp-001', state: 'queued' };
130				await route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ data: { comparisonDispatch: result } }) });
131			} else if (body.query.includes('Comparisons')) {
132				await route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify({ data: { comparisons: [] } }) });
133			} else {
134				await route.continue();
135			}
136		});
137	}
